text = text.split()
import itertools

def neighbors(i, j):
  x = [j - 1, j, j + 1]
  x = [p for p in x if p >= 0 and p < len(text[0])]
  y = [i - 1, i, i + 1]
  y = [p for p in y if p >= 0 and p < len(text[0])]
  #print(i, j, x, y)
  return [p for p in itertools.product(y, x) if p != (i, j)]
  
ans = []
total = 0
for i in range(len(text)):
  s = ''
  for j in range(len(text[0])):
    if text[i][j] == '@':
      rolls = len([k for k in neighbors(i, j) if text[k[0]][k[1]] == '@'])
      if rolls < 4:
        total += 1
        s += 'x'
      else:
        s += '@'
    else:
      s += text[i][j]
  ans.append(s)
for i in ans:
  print(i)
print(total)

# part 2
from collections import deque
text = [[j for j in i] for i in text]
q = deque()
q_set = set()
total = 0
for i in range(len(text)):
  for j in range(len(text[0])):
    if text[i][j] == '@':
      if len([k for k in neighbors(i, j) if text[k[0]][k[1]] == '@']) < 4:
        q.append((i, j))
        q_set.add((i, j))
while q:
  i, j = q.popleft()
  q_set.remove((i, j))
  total += 1
  text[i][j] = '.'
  for k, l in neighbors(i, j):
    if (k, l) in q_set:
      continue
    if text[k][l] == '@' and len([k for k in neighbors(k, l) if text[k[0]][k[1]] == '@']) < 4:
      q.append((k, l))
      q_set.add((k, l))
print(total)
